@@ -408,14 +408,57 @@
     <script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
     <script src="https://cdn.jsdelivr.net/npm/swiper/swiper-bundle.min.js"></script>
     <script src="https://cdnjs.cloudflare.com/ajax/libs/aos/2.3.4/aos.js"></script>
     <!-- PureCounter Library -->
-    <script src="https://cdn.jsdelivr.net/npm/purecounterjs/dist/purecounter.min.js"></script>
+    <script src="https://cdnjs.cloudflare.com/ajax/libs/purecounter/1.5.0/purecounter.min.js"></script>
     <script>
         AOS.init({
             duration: 1000,
             once: true
         });
+
+        // Initialize PureCounter
+        new PureCounter();
+        
+        // Alternative vanilla counter if PureCounter fails
+        function initCounters() {
+            const counters = document.querySelectorAll('.purecounter');
+            counters.forEach(counter => {
+                const start = parseInt(counter.dataset.purecounterStart) || 0;
+                const end = parseInt(counter.dataset.purecounterEnd) || 0;
+                const duration = parseInt(counter.dataset.purecounterDuration) || 2;
+                
+                if (end > 0) {
+                    const increment = end / (duration * 100);
+                    let current = start;
+                    
+                    const updateCounter = () => {
+                        if (current < end) {
+                            current += increment;
+                            counter.textContent = Math.floor(current).toLocaleString();
+                            setTimeout(updateCounter, 1000 / 100);
+                        } else {
+                            counter.textContent = end.toLocaleString();
+                        }
+                    };
+                    
+                    // Start animation when in viewport
+                    const observer = new IntersectionObserver((entries) => {
+                        entries.forEach(entry => {
+                            if (entry.isIntersecting && current < end) {
+                                updateCounter();
+                                observer.unobserve(entry.target);
+                            }
+                        });
+                    });
+                    
+                    observer.observe(counter);
+                }
+            });
+        }
+        
+        // Initialize on page load
+        document.addEventListener('DOMContentLoaded', initCounters);
     </script>
     <script src="./js/common.js"></script>
     <script src="./js/index.js"></script>
   </body>

